import{c as s,S as a,j as i,m as t}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"Subscribe & Update","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/subscribe-update.md","filePath":"sharing/subscribe-update.md","lastUpdated":1783418049000}'),n={name:"sharing/subscribe-update.md"};function o(r,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="subscribe-update" tabindex="-1">Subscribe &amp; Update <a class="header-anchor" href="#subscribe-update" aria-label="Permalink to “Subscribe &amp; Update”">​</a></h1><p>Installing a bundle from a GitHub release URL makes you a subscriber: the vault remembers where the bundle came from, and can ask that source for newer versions.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check-updates</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>jay.drone-delivery  v1.2.0 → v1.3.0 available</span></span>
<span class="line"><span>team.obs-pack       v2.0.0 — up to date</span></span>
<span class="line"><span>old.zip-install     v1.0.0 — unchecked (no version protocol for this source)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 update(s) available — install with: knowlery bundle update &lt;id&gt; (or --all)</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jay.drone-delivery</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # or --all</span></span></code></pre></div><p>Updates go through the <strong>full install pipeline</strong> — conformance gate, version gate, path safety — and the replacement is staged: if anything fails, the installed version is untouched.</p><p>In Obsidian, the dashboard&#39;s <em>Installed bundles</em> section has a <strong>Check updates</strong> button with per-bundle Update buttons.</p><h2 id="the-subscription-model" tabindex="-1">The subscription model <a class="header-anchor" href="#the-subscription-model" aria-label="Permalink to “The subscription model”">​</a></h2><ul><li><strong>Pull, not push.</strong> Nothing checks in the background; you (or your agent, on whatever cadence you&#39;ve agreed) run the check. <code>knowlery sync</code> stays offline by design — <code>check-updates</code> is its network-side sibling.</li><li><strong>Permission is membership.</strong> Updates come from the same source you installed from, with the same access rules — org members keep receiving updates as long as they&#39;re in the org. See <a href="./grant-access">Grant access</a>.</li><li><strong>The status taxonomy is honest</strong>: <code>unchecked</code> means the source carries no version-discovery protocol (a bare zip URL); <code>skipped</code> means a private source needs <code>gh</code>; neither is an error.</li></ul><h2 id="local-modifications-are-protected" tabindex="-1">Local modifications are protected <a class="header-anchor" href="#local-modifications-are-protected" aria-label="Permalink to “Local modifications are protected”">​</a></h2><p>If you edited files inside <code>Library/&lt;bundle-id&gt;/</code>, updating would overwrite your changes — so it refuses, naming exactly which files were edited, added, or deleted. The convention: <strong>installed knowledge is referenced, not edited</strong> — put your own insights in your own pages and link to the bundle&#39;s. If you&#39;re sure, <code>--force</code> overwrites.</p><h2 id="versioning-notes" tabindex="-1">Versioning notes <a class="header-anchor" href="#versioning-notes" aria-label="Permalink to “Versioning notes”">​</a></h2><p>Bundle versions are stable dotted-numeric (<code>1.2.0</code>, <code>1.10.0</code> — compared numerically, so <code>1.10 &gt; 1.9</code>). There is no downgrade command: to roll back, re-install the older release&#39;s URL directly.</p>`,13)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
